// src/pages/SellerDashboard.js
import React, { useState } from "react";
import "./SellerDashboard.css";
import UploadBox from "../components/Upload"; // make sure the filename matches

function SellerDashboard() {
  const [products, setProducts] = useState([]);
  const [images, setImages] = useState([]); // store uploaded images

  const [form, setForm] = useState({
    name: "",
    description: "",
    category: "Earphone",
    price: "",
    offerPrice: "",
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setProducts([...products, { ...form, images }]);
    setForm({ name: "", description: "", category: "Earphone", price: "", offerPrice: "" });
    setImages([]); // clear images after adding
  };

  const handleFileChange = (e, index) => {
    const file = e.target.files[0];
    if (file) {
      const newImages = [...images];
      newImages[index] = URL.createObjectURL(file);
      setImages(newImages);
    }
  };

  return (
    <div className="seller-dashboard">
      <aside className="sidebar">
        <h1 className="logo"></h1>
        <nav>
          <ul>
            <li className="active">➕ Add Product</li>
            <li>📦 Product List</li>
            <li>📝 Orders</li>
          </ul>
        </nav>
      </aside>

      <main className="main-content">
        <h2 className="page-title">Add Product</h2>

        <form className="product-form" onSubmit={handleSubmit}>
          {/* Upload section */}
          

          <label>Product Name</label>
          <input
            type="text"
            name="name"
            placeholder="Type here"
            value={form.name}
            onChange={handleChange}
            required
          />

          <label>Product Description</label>
          <textarea
            name="description"
            placeholder="Type here"
            value={form.description}
            onChange={handleChange}
          ></textarea>

          <div className="row">
            <div>
              <label>Category</label>
              <select name="category" value={form.category} onChange={handleChange}>
                <option>Earphone</option>
                <option>Smartphone</option>
                <option>Laptop</option>
                <option>Smartwatch</option>
                <option>Other</option>
              </select>
            </div>

            <div>
              <label>Product Price</label>
              <input
                type="number"
                name="price"
                placeholder="0"
                value={form.price}
                onChange={handleChange}
                required
              />
            </div>

            <div>
              <label>Offer Price</label>
              <input
                type="number"
                name="offerPrice"
                placeholder="0"
                value={form.offerPrice}
                onChange={handleChange}
              />
            </div>
          </div>

          <button type="submit" className="add-btn">ADD</button>
        </form>

        {/* Seller's products */}
        <h3 className="list-title">Your Listed Items</h3>
        <div className="product-list">
          {products.map((p, idx) => (
            <div key={idx} className="product-card">
              <h4>{p.name}</h4>
              <p>{p.description}</p>
              <p><b>Category:</b> {p.category}</p>
              <p><b>Price:</b> ₹{p.price}</p>
              {p.offerPrice && <p><b>Offer:</b> ₹{p.offerPrice}</p>}
              {p.images && p.images.map((img, i) => (
                <img key={i} src={img} alt="product" style={{ width: "50px", marginRight: "5px" }} />
              ))}
            </div>
          ))}
        </div>
      </main>
    </div>
  );
}

export default SellerDashboard;
